t=test_expr;
if(!t)
goto done;
do
body_statement
while(test_expr);
done:
相应地，进一步将它翻译成 goto 语句:
t=test_expr;
if(!t)
goto done;
loop:
body_statement
t=test_expr;
if(t)
goto loop;
done:
